import { useState } from 'react';
import API from '../services/axios';

const T = "-apple-system, BlinkMacSystemFont, 'SF Pro Display', 'Segoe UI', sans-serif";
const GOLD = '#D4AF37';

const TOPICS = ['Event Quality', 'App Experience', 'Booking Process', 'Customer Support', 'Pricing', 'Other'];

export default function FeedbackChatbot() {
  const [open, setOpen] = useState(false);
  const [step, setStep] = useState(0);
  const [form, setForm] = useState(() => {
    // Auto-fill name and email from logged-in user
    try {
      const user = JSON.parse(localStorage.getItem('user') || '{}');
      return { topic: '', rating: 0, details: '', name: user.name || '', email: user.email || '' };
    } catch { return { topic: '', rating: 0, details: '', name: '', email: '' }; }
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const next = () => setStep(s => s + 1);

  const submit = async () => {
    setLoading(true);
    setError('');
    try {
      await API.post('/feedback', {
        topic: form.topic,
        rating: form.rating,
        details: form.details,
        name: form.name || 'Anonymous',
        email: form.email || '',
      });
      setStep(5);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to submit. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const reset = () => {
    setStep(0);
    setError('');
    try {
      const user = JSON.parse(localStorage.getItem('user') || '{}');
      setForm({ topic: '', rating: 0, details: '', name: user.name || '', email: user.email || '' });
    } catch {
      setForm({ topic: '', rating: 0, details: '', name: '', email: '' });
    }
  };

  const inputStyle = {
    width: '100%', padding: '10px 14px', background: '#1a1a1a',
    border: '1px solid rgba(255,255,255,0.1)', borderRadius: '8px',
    color: '#fff', fontSize: '0.88rem', fontFamily: T, outline: 'none',
    boxSizing: 'border-box', transition: 'border-color 0.2s',
  };

  return (
    <>
      <style>{`
        @keyframes slideUp { from{opacity:0;transform:translateY(12px)} to{opacity:1;transform:translateY(0)} }
        @keyframes fadeIn  { from{opacity:0} to{opacity:1} }
        .fb-input::placeholder { color: #444; }
        .fb-btn:hover { opacity: 0.85; }
        .fb-topic:hover { border-color: ${GOLD} !important; color: ${GOLD} !important; }
      `}</style>

      {/* FAB */}
      <button onClick={() => setOpen(o => !o)} style={{
        position: 'fixed', bottom: '28px', right: '28px', zIndex: 1000,
        width: '54px', height: '54px', borderRadius: '50%',
        background: open ? '#1a1a1a' : GOLD,
        border: open ? '1px solid rgba(255,255,255,0.12)' : 'none',
        cursor: 'pointer', fontSize: '1.3rem',
        boxShadow: open ? '0 4px 20px rgba(0,0,0,0.4)' : '0 8px 28px rgba(212,175,55,0.4)',
        transition: 'all 0.3s', display: 'flex', alignItems: 'center', justifyContent: 'center',
        color: open ? '#fff' : '#000',
      }}>
        {open ? '✕' : '💬'}
      </button>

      {/* Panel */}
      {open && (
        <div style={{
          position: 'fixed', bottom: '96px', right: '28px', zIndex: 999,
          width: '340px', background: '#0d0d0d',
          border: '1px solid rgba(255,255,255,0.1)', borderRadius: '20px',
          overflow: 'hidden', fontFamily: T,
          boxShadow: '0 24px 60px rgba(0,0,0,0.7)',
          animation: 'slideUp 0.3s ease',
        }}>

          {/* Header */}
          <div style={{ padding: '1rem 1.2rem', borderBottom: '1px solid rgba(255,255,255,0.06)', display: 'flex', alignItems: 'center', gap: '10px' }}>
            <div style={{ width: '34px', height: '34px', background: 'rgba(212,175,55,0.1)', border: '1px solid rgba(212,175,55,0.2)', borderRadius: '9px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.95rem', flexShrink: 0 }}>✦</div>
            <div>
              <p style={{ color: '#fff', fontWeight: 700, fontSize: '0.9rem', margin: 0 }}>Feedback</p>
              <p style={{ color: '#555', fontSize: '0.72rem', margin: 0 }}>Help us improve NexEvent</p>
            </div>
            {/* Progress dots */}
            <div style={{ marginLeft: 'auto', display: 'flex', gap: '5px' }}>
              {[0,1,2,3,4].map(i => (
                <div key={i} style={{
                  width: '6px', height: '6px', borderRadius: '50%',
                  background: i < step ? GOLD : i === step ? GOLD : '#2a2a2a',
                  opacity: i < step ? 1 : i === step ? 1 : 0.4,
                  transition: 'all 0.3s',
                }} />
              ))}
            </div>
          </div>

          {/* Body */}
          <div style={{ padding: '1.2rem' }}>

            {/* Step 0 — Topic */}
            {step === 0 && (
              <div style={{ animation: 'fadeIn 0.3s ease' }}>
                <p style={{ color: '#A0A0A0', fontSize: '0.86rem', marginBottom: '1rem', lineHeight: 1.5 }}>
                  What would you like to share feedback about?
                </p>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                  {TOPICS.map(t => (
                    <button key={t} className="fb-topic"
                      onClick={() => { setForm(f => ({ ...f, topic: t })); next(); }}
                      style={{ padding: '10px 14px', background: '#111', border: '1px solid rgba(255,255,255,0.07)', borderRadius: '9px', color: '#A0A0A0', textAlign: 'left', cursor: 'pointer', fontFamily: T, fontSize: '0.86rem', fontWeight: 500, transition: 'all 0.2s' }}>
                      {t}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {/* Step 1 — Rating */}
            {step === 1 && (
              <div style={{ animation: 'fadeIn 0.3s ease' }}>
                <p style={{ color: '#A0A0A0', fontSize: '0.86rem', marginBottom: '1rem', lineHeight: 1.5 }}>
                  Rate your experience with <strong style={{ color: '#fff' }}>{form.topic}</strong>
                </p>
                <div style={{ display: 'flex', gap: '8px', justifyContent: 'center', marginBottom: '1.2rem' }}>
                  {[1,2,3,4,5].map(n => (
                    <button key={n} onClick={() => setForm(f => ({ ...f, rating: n }))}
                      style={{
                        width: '46px', height: '46px', borderRadius: '10px',
                        border: `1px solid ${form.rating >= n ? GOLD : 'rgba(255,255,255,0.08)'}`,
                        background: form.rating >= n ? 'rgba(212,175,55,0.15)' : '#111',
                        cursor: 'pointer', fontSize: '1.3rem', transition: 'all 0.2s',
                        color: form.rating >= n ? GOLD : '#555',
                      }}>★</button>
                  ))}
                </div>
                {form.rating > 0 && (
                  <p style={{ textAlign: 'center', color: GOLD, fontSize: '0.78rem', fontWeight: 600, marginBottom: '1rem' }}>
                    {['','😞 Poor','😕 Fair','😐 Good','😊 Great','🤩 Excellent'][form.rating]}
                  </p>
                )}
                <button onClick={next} disabled={!form.rating} style={{
                  width: '100%', padding: '11px',
                  background: form.rating ? GOLD : '#222',
                  color: form.rating ? '#000' : '#555',
                  border: 'none', borderRadius: '9px',
                  cursor: form.rating ? 'pointer' : 'not-allowed',
                  fontWeight: 700, fontSize: '0.88rem', fontFamily: T,
                }}>Continue</button>
              </div>
            )}

            {/* Step 2 — Details */}
            {step === 2 && (
              <div style={{ animation: 'fadeIn 0.3s ease' }}>
                <p style={{ color: '#A0A0A0', fontSize: '0.86rem', marginBottom: '1rem', lineHeight: 1.5 }}>
                  Any details you'd like to share? <span style={{ color: '#444' }}>(optional)</span>
                </p>
                <textarea className="fb-input" value={form.details}
                  onChange={e => setForm(f => ({ ...f, details: e.target.value }))}
                  placeholder="Tell us more..."
                  rows={3}
                  style={{ ...inputStyle, resize: 'none', lineHeight: 1.6, marginBottom: '1rem' }}
                  onFocus={e => e.target.style.borderColor = GOLD}
                  onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.1)'}
                />
                <button onClick={next} style={{ width: '100%', padding: '11px', background: GOLD, color: '#000', border: 'none', borderRadius: '9px', cursor: 'pointer', fontWeight: 700, fontSize: '0.88rem', fontFamily: T }}>
                  Continue
                </button>
              </div>
            )}

            {/* Step 3 — Name */}
            {step === 3 && (
              <div style={{ animation: 'fadeIn 0.3s ease' }}>
                <p style={{ color: '#A0A0A0', fontSize: '0.86rem', marginBottom: '1rem', lineHeight: 1.5 }}>
                  Your name <span style={{ color: '#444' }}>(optional)</span>
                </p>
                <input className="fb-input" value={form.name}
                  onChange={e => setForm(f => ({ ...f, name: e.target.value }))}
                  placeholder="Your name"
                  style={{ ...inputStyle, marginBottom: '1rem' }}
                  onFocus={e => e.target.style.borderColor = GOLD}
                  onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.1)'}
                />
                <button onClick={next} style={{ width: '100%', padding: '11px', background: GOLD, color: '#000', border: 'none', borderRadius: '9px', cursor: 'pointer', fontWeight: 700, fontSize: '0.88rem', fontFamily: T }}>
                  Continue
                </button>
              </div>
            )}

            {/* Step 4 — Email + Submit */}
            {step === 4 && (
              <div style={{ animation: 'fadeIn 0.3s ease' }}>
                <p style={{ color: '#A0A0A0', fontSize: '0.86rem', marginBottom: '1rem', lineHeight: 1.5 }}>
                  Your email <span style={{ color: '#444' }}>(optional)</span>
                </p>
                <input className="fb-input" type="email" value={form.email}
                  onChange={e => setForm(f => ({ ...f, email: e.target.value }))}
                  placeholder="you@example.com"
                  style={{ ...inputStyle, marginBottom: '1rem' }}
                  onFocus={e => e.target.style.borderColor = GOLD}
                  onBlur={e => e.target.style.borderColor = 'rgba(255,255,255,0.1)'}
                />
                {error && (
                  <div style={{ background: 'rgba(255,69,58,0.1)', border: '1px solid rgba(255,69,58,0.2)', borderRadius: '8px', padding: '10px 12px', marginBottom: '1rem', color: '#FF453A', fontSize: '0.8rem' }}>
                    {error}
                  </div>
                )}
                <button onClick={submit} disabled={loading} style={{
                  width: '100%', padding: '11px',
                  background: loading ? '#222' : GOLD,
                  color: loading ? '#555' : '#000',
                  border: 'none', borderRadius: '9px',
                  cursor: loading ? 'not-allowed' : 'pointer',
                  fontWeight: 700, fontSize: '0.88rem', fontFamily: T,
                  transition: 'all 0.2s',
                }}>
                  {loading ? 'Submitting...' : 'Submit Feedback ✦'}
                </button>
              </div>
            )}

            {/* Step 5 — Done */}
            {step === 5 && (
              <div style={{ textAlign: 'center', padding: '1rem 0', animation: 'fadeIn 0.4s ease' }}>
                <div style={{ width: '52px', height: '52px', background: 'rgba(48,209,88,0.1)', border: '1px solid rgba(48,209,88,0.25)', borderRadius: '14px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.5rem', margin: '0 auto 1rem' }}>✓</div>
                <p style={{ color: '#fff', fontWeight: 700, fontSize: '1rem', margin: '0 0 6px' }}>Thank you!</p>
                <p style={{ color: '#555', fontSize: '0.84rem', margin: '0 0 1.4rem', lineHeight: 1.5 }}>Your feedback helps us improve NexEvent.</p>
                <button onClick={() => { reset(); setOpen(false); }}
                  style={{ padding: '9px 24px', background: 'transparent', color: GOLD, border: `1px solid rgba(212,175,55,0.3)`, borderRadius: '9px', cursor: 'pointer', fontWeight: 600, fontSize: '0.84rem', fontFamily: T, transition: 'all 0.2s' }}
                  onMouseEnter={e => e.currentTarget.style.background = 'rgba(212,175,55,0.08)'}
                  onMouseLeave={e => e.currentTarget.style.background = 'transparent'}>
                  Close
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </>
  );
}
